var body = $input.first().json.body || $input.first().json;

if (!body.tenantId) {
  throw new Error('tenantId is required');
}

function esc(v) { return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'"; }

var limit = parseInt(body.limit) || 50;
var offset = parseInt(body.offset) || 0;
var status = body.status || null;
var source = body.source || null;
var search = body.search || null;
var listId = body.listId || null;

var whereClause = "WHERE s.tenant_id = " + esc(body.tenantId) + "::uuid";
if (status) {
  whereClause += " AND s.status = " + esc(status);
}
if (source) {
  whereClause += " AND s.source = " + esc(source);
}
if (search) {
  var searchEsc = esc('%' + search + '%');
  whereClause += " AND (s.email ILIKE " + searchEsc + " OR s.nom ILIKE " + searchEsc + " OR s.prenom ILIKE " + searchEsc + ")";
}
if (listId) {
  whereClause += " AND s.id IN (SELECT subscriber_id FROM subscriber_list_members WHERE list_id = " + esc(listId) + "::uuid)";
}

var countQuery = "SELECT COUNT(*) as total FROM subscribers s " + whereClause;
var listQuery = "SELECT s.id, s.tenant_id AS \"tenantId\", s.email, s.telephone, s.nom, s.prenom, s.entreprise, s.status, s.source, s.tags, s.created_at AS \"createdAt\", s.updated_at AS \"updatedAt\" FROM subscribers s " + whereClause + " ORDER BY s.created_at DESC LIMIT " + limit + " OFFSET " + offset;

return [{ json: { tenantId: body.tenantId, limit: limit, offset: offset, countQuery: countQuery, listQuery: listQuery } }];

var items = $('06. List Query').all();
var subscribers = items.map(function(item) { return item.json; }).filter(function(s) { return s.id; });
var countResult = $('05. Count Query').first().json;
var total = parseInt(countResult.total) || 0;
var limit = $('02. Parser').first().json.limit;
var offset = $('02. Parser').first().json.offset;

return [{ json: { subscribers: subscribers, total: total, limit: limit, offset: offset } }];
